// Build the Gemini request body cleanly in code, avoiding JSON-in-JSON escaping issues.
// This runs once per incoming email item.

const email = $input.item.json;

// Pull the fields the Gmail Trigger gives us, with safe fallbacks.
const from = email.From || 'unknown';
const subject = email.Subject || '(no subject)';
const content = email.snippet || '(no content)';

// The instruction prompt. Using a normal JS template literal — newlines are fine here
// because we are NOT inside a JSON string; we build a real object below.
const prompt = `You are an email triage assistant for a small business. Analyze the email below and return a JSON object with exactly these fields:

- category: one of [sales_lead, support, billing, spam, other]
- name: the sender's first and last name, or null if not found
- company: the sender's company name, or null if not found
- intent: one sentence describing what the sender wants
- urgency: integer 1-5 where 1=not urgent, 5=extremely urgent
- draft_reply: a short, professional reply draft the human can edit and send

Rules:
- Return ONLY valid JSON, no explanation, no markdown, no code fences
- Never fabricate information not present in the email
- If a field cannot be determined, use null
- urgency 5 is reserved for legal threats, outages, or explicit deadlines today

Email to analyze:
From: ${from}
Subject: ${subject}
Content: ${content}`;

// Build the full Gemini request body as a real JS object.
// n8n will serialize this to valid JSON automatically — no manual escaping needed.
const geminiBody = {
  contents: [
    {
      parts: [
        { text: prompt }
      ]
    }
  ],
  generationConfig: {
    responseMimeType: "application/json",
    responseSchema: {
      type: "object",
      properties: {
        category: { type: "string", enum: ["sales_lead", "support", "billing", "spam", "other"] },
        name: { type: "string", nullable: true },
        company: { type: "string", nullable: true },
        intent: { type: "string" },
        urgency: { type: "integer" },
        draft_reply: { type: "string" }
      },
      required: ["category", "name", "company", "intent", "urgency", "draft_reply"]
    }
  }
};

// Pass both the original email (so later nodes still have it) and the request body.
return {
  json: {
    ...email,
    geminiBody: geminiBody
  }
};

// PHASE 5: Parse Gemini's response, validate it against our schema, and flag
// anything malformed so it can be routed to a safe-fail branch instead of
// silently writing garbage downstream. This is the reliability core of the agent.
const response = $input.item.json;
// --- Step 1: Safely dig out the model's text output ---------------------------
let rawText;
try {
  rawText = response.candidates[0].content.parts[0].text;
} catch (e) {
  rawText = null;
}
// --- Step 2: Parse the text as JSON inside a try/catch ------------------------
let parsed = null;
let parseError = null;
if (rawText) {
  try {
    parsed = JSON.parse(rawText);
  } catch (e) {
    parseError = `JSON parse failed: ${e.message}`;
  }
} else {
  parseError = 'No text found in Gemini response (unexpected response shape).';
}
// --- Step 3: Validate the parsed object against our expected schema -----------
const allowedCategories = ['sales_lead', 'support', 'billing', 'spam', 'other'];
const validationErrors = [];
if (parsed) {
  if (!allowedCategories.includes(parsed.category)) {
    validationErrors.push(`category "${parsed.category}" not in allowed list`);
  }
  if (typeof parsed.intent !== 'string' || parsed.intent.trim() === '') {
    validationErrors.push('intent missing or empty');
  }
  if (!Number.isInteger(parsed.urgency) || parsed.urgency < 1 || parsed.urgency > 5) {
    validationErrors.push(`urgency "${parsed.urgency}" is not an integer 1-5`);
  }
  if (typeof parsed.draft_reply !== 'string' || parsed.draft_reply.trim() === '') {
    validationErrors.push('draft_reply missing or empty');
  }
}
// --- Step 4: Decide validity and build a clean, flat output -------------------
const isValid = parsed !== null && validationErrors.length === 0;

// CHANGED: reference 'Get many messages' instead of 'Gmail Trigger'
const email = $('Get many messages').item.json;

// ADDED: carry message_id forward so mark-as-read nodes can use it
const messageId = email.id;

return {
  json: {
    is_valid: isValid,
    error_reason: isValid
      ? null
      : [parseError, ...validationErrors].filter(Boolean).join('; '),
    email_from: email.From ?? null,
    email_subject: email.Subject ?? null,
    email_snippet: email.snippet ?? null,
    // ADDED: message_id for mark-as-read
    message_id: messageId,
    category: parsed?.category ?? null,
    name: parsed?.name ?? null,
    company: parsed?.company ?? null,
    intent: parsed?.intent ?? null,
    urgency: parsed?.urgency ?? null,
    draft_reply: parsed?.draft_reply ?? null,
    _raw_model_text: rawText,
  },
};
